/* BTBadge styles — Figma 72:1516.
   All colours via @btech/tokens CSS vars — no hex fallbacks. */

.bt-badge {
  display: inline-flex;
  align-items: center;
  gap: var(--space-xs);
  padding: var(--space-xs) var(--space-sm);
  border-radius: var(--radius-rd);
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-xs);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  letter-spacing: 0;
  white-space: nowrap;
}

/* ── Normal mode ── */
.bt-badge--success { background: var(--color-ext-success-subtler); color: var(--color-ext-success-bold); }
.bt-badge--waiting { background: var(--color-ext-warning-subtler); color: var(--color-ext-warning-bold); }
.bt-badge--neutral { background: var(--bg-secondary);              color: var(--text-primary); }
.bt-badge--draft   { background: var(--color-ext-info-subtler);    color: var(--color-ext-info-bold); }
.bt-badge--reject  { background: var(--color-ext-error-subtler);   color: var(--color-ext-error-bold); }
.bt-badge--custom  { background: var(--color-brand-secondary-subtle); color: var(--color-brand-secondary-bold); }

/* ── Reverse mode — solid bg + inverse text ── */
.bt-badge--success.bt-badge--reverse { background: var(--color-ext-success); color: var(--text-inverse); }
.bt-badge--waiting.bt-badge--reverse { background: var(--color-ext-warning); color: var(--text-inverse); }
.bt-badge--neutral.bt-badge--reverse { background: var(--bg-tertiary);       color: var(--text-inverse); }
.bt-badge--draft.bt-badge--reverse   { background: var(--color-ext-info);    color: var(--text-inverse); }
.bt-badge--reject.bt-badge--reverse  { background: var(--color-ext-error);   color: var(--text-inverse); }
.bt-badge--custom.bt-badge--reverse  { background: var(--color-brand-secondary); color: var(--text-inverse); }

.bt-badge__label {
  flex-shrink: 0;
}

/**
 * BTBadge — status label atom.
 * Sliced from Figma `Badge` (node 72:1516). Mirrors @btech/ui-vue BTBadge
 * one-to-one (same prop names, same variant logic, same render priority).
 *
 * ## Usage:
 * ```tsx
 * // Normal
 * <BTBadge label="Approved" variant="success" />
 *
 * // With left icon
 * <BTBadge label="Waiting" variant="waiting" leftIcon={<ClockIcon size={16} />} />
 *
 * // Reverse (solid bg + white text)
 * <BTBadge label="Rejected" variant="reject" reverseColors />
 * ```
 */
import * as React from 'react';
import type { BTBadgeProps } from './BTBadge.types';
import './BTBadge.css';

/**
 * Status label pill. See file header for usage examples.
 */
export const BTBadge = React.forwardRef<HTMLSpanElement, BTBadgeProps>(
  (
    {
      label = 'Badge',
      variant = 'success',
      reverseColors = false,
      leftIcon,
      rightIcon,
      className,
      ...rest
    },
    ref,
  ) => {
    const classes = [
      'bt-badge',
      `bt-badge--${variant}`,
      reverseColors ? 'bt-badge--reverse' : '',
      className ?? '',
    ]
      .filter(Boolean)
      .join(' ');

    return (
      <span ref={ref} className={classes} data-testid="bt-badge" {...rest}>
        {leftIcon}
        <span className="bt-badge__label">{label}</span>
        {rightIcon}
      </span>
    );
  },
);

BTBadge.displayName = 'BTBadge';

/**
 * Props for {@link BTBadge}.
 *
 * @example
 * ```tsx
 * <BTBadge label="Approved" variant="success" />
 * <BTBadge label="Draft" variant="draft" reverseColors />
 * <BTBadge label="Waiting" variant="waiting" leftIcon={<ClockIcon />} />
 * ```
 */
export interface BTBadgeProps {
  /** Text displayed inside the badge. @default 'Badge' */
  label?: string;
  /**
   * Color palette variant.
   * @default 'success'
   */
  variant?: 'success' | 'waiting' | 'neutral' | 'draft' | 'reject' | 'custom';
  /** When `true`: solid background + white text. @default false */
  reverseColors?: boolean;
  /** Optional 16×16 node rendered to the left of the label. */
  leftIcon?: React.ReactNode;
  /** Optional 16×16 node rendered to the right of the label. */
  rightIcon?: React.ReactNode;
  /** Additional CSS class names. */
  className?: string;
}
